	@Test
	void datatypeFilterRejectsMismatchingInlinedLiteralIds(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			Literal intObject = VF.createLiteral("7", XSD.INT);
			Literal nonCanonicalIntObject = VF.createLiteral("007", XSD.INT);
			Literal integerObject = VF.createLiteral("7", XSD.INTEGER);
			Literal stringObject = VF.createLiteral("7");
			IRI iriObject = VF.createIRI("http://example.com/value/iri");
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				connection.add(VF.createIRI("http://example.com/s/int"), MIXED_OBJECT, intObject);
				connection.add(VF.createIRI("http://example.com/s/non-canonical-int"), MIXED_OBJECT,
						nonCanonicalIntObject);
				connection.add(VF.createIRI("http://example.com/s/integer"), MIXED_OBJECT, integerObject);
				connection.add(VF.createIRI("http://example.com/s/string"), MIXED_OBJECT, stringObject);
				connection.add(VF.createIRI("http://example.com/s/iri"), MIXED_OBJECT, iriObject);
				connection.commit();
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
				LmdbPlannerAwait.awaitSketchesReady(store);

				String query = String.join("\n",
						"PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>",
						"SELECT ?o WHERE {",
						"  ?s <http://example.com/p/mixed-object> ?o .",
						"  FILTER(datatype(?o) = xsd:int)",
						"}");

				List<Value> resultObjects = new ArrayList<>();
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						resultObjects.add(result.next().getValue("o"));
					}
				}
				assertEquals(2, resultObjects.size());
				assertTrue(resultObjects.contains(intObject));
				assertTrue(resultObjects.contains(nonCanonicalIntObject));

				Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);
				StatementPattern pattern = findStatementPattern((TupleExpr) explanation.tupleExpr(), MIXED_OBJECT, "o");
				assertNotNull(pattern, explanation::toString);
				assertEquals("object:XSD_INT", pattern.getStringMetricPlanned("optimizer.idFilter"),
						explanation::toString);
				assertEquals(2L, pattern.getSourceRowsMatchedActual(), explanation::toString);
				assertTrue(pattern.getSourceRowsFilteredActual() >= 3L, explanation::toString);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static StatementPattern findStatementPattern(TupleExpr tupleExpr, IRI predicate, String objectName) {
		List<StatementPattern> matches = new ArrayList<>(1);
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (predicate.equals(node.getPredicateVar().getValue())
						&& objectName.equals(node.getObjectVar().getName())) {
					matches.add(node);
				}
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}
